update major set core_course_learning = '产品设计史（工业设计/手工艺）、人机工程学（交互/舒适）、材料选择（塑料/金属/木材）、造型设计（形态/比例/色彩）、原型制作（3D打印/手工模型）。', practical_skill_development='产品造型（如手机/家电）设计实践、人机交互（如界面/按键）测试模拟、原型（如功能模型）制作实训、毕业论文（智能产品设计用户体验研究）。', skill_expansion='智能产品设计（如IoT设备）技术应用能力、可持续设计（如可回收材料）实践技能、产品设计市场（如用户调研）分析能力。'  where code='130504';
update major set core_course_learning = '服装史（中西方服装史/民族服饰）、服装结构（立体裁剪/平面制版）、面料设计（织造/印染/后整理）、服饰品设计（配饰/鞋包）、服装营销（品牌/陈列）。', practical_skill_development='服装制版（如连衣裙）实践、面料改造（如扎染/刺绣）操作实训、服饰品（如耳环）设计模拟、毕业论文（汉服当代改良设计研究）。', skill_expansion='3D服装设计（如CLO3D）技术应用能力、可持续时尚（如旧衣改造）创意技能、服装品牌（如快时尚）运营实务能力。'  where code='130505';
update major set core_course_learning = '公共艺术理论（城市雕塑/壁画/装置）、公共空间设计（社区/广场/公园）、材料工艺（石材/金属/玻璃）、公众参与（调研/互动）、项目管理（预算/审批/落地）。', practical_skill_development='公共雕塑（如城市地标）方案设计实训、壁画（如地铁站）绘制实践、公共设施（如座椅/路灯）设计模拟、毕业论文（社区公共艺术实践研究）。', skill_expansion='公共艺术策展（如户外展览）能力、公众参与（如工作坊）组织技能、公共艺术政策（如《城市雕塑管理办法》）解读能力。'  where code='130506';
update major set core_course_learning = '工艺美术史（陶瓷/漆器/织绣）、传统工艺（景泰蓝/雕漆/苏绣）、材料工艺（釉料/天然漆/蚕丝）、制作技法（雕刻/镶嵌/编织）、现代工艺（创新材料/技术）。', practical_skill_development='传统工艺（如陶瓷拉坯）实践、现代工艺（如树脂铸造）技法训练、工艺美术品（如首饰/摆件）制作模拟、毕业论文（传统工艺活态传承研究）。', skill_expansion='非遗工艺（如苗绣）活化能力、工艺美术与时尚（如文创产品）融合技能、工艺美术教育（如非遗工坊）教学能力。'  where code='130507';
update major set core_course_learning = '数字媒体理论（动画/游戏/交互）、数字工具（Photoshop/AE/3ds Max）、动画原理（运动规律/骨骼绑定）、游戏设计（角色/场景/关卡）、交互设计（用户体验/界面）。', practical_skill_development='动画制作（如短片）全流程实践、游戏场景（如3D建模）设计实训、交互界面（如APP）开发模拟、毕业论文（生成式AI在数字媒体中的应用研究）。', skill_expansion='虚拟制片（如LED拍摄）技术应用能力、元宇宙数字媒体（如虚拟偶像）创作技能、数字媒体艺术教育（如数字绘画课）组织能力。'  where code='130508';
update major set core_course_learning = '艺术与科技理论（跨学科融合）、科技史（工业革命/数字革命）、交互技术（传感器/脑机接口）、数字艺术（AI/VR/AR）、科技伦理（隐私/版权）。', practical_skill_development='科技艺术装置（如互动投影）创作实践、交互设备（如体感控制器）调试实训、数字艺术（如AI绘画）生成模拟、毕业论文（科技对艺术创作的影响研究）。', skill_expansion='元宇宙艺术（如虚拟展览）策划能力、AI艺术工具（如DALL-E）高级应用技能、科技艺术政策（如数据安全法）合规能力。'  where code='130509T';
update major set core_course_learning = '陶瓷史（青瓷/白瓷/彩瓷）、陶瓷工艺（拉坯/利坯/上釉）、材料科学（釉料/坯体）、烧制技术（柴烧/电烧/气烧）、陶瓷设计（器型/装饰/功能）。', practical_skill_development='陶瓷成型（如手工拉坯）实践、釉料配方（如青釉/霁红）调试实训、烧制（如窑炉操作）技术模拟、毕业论文（宋代汝窑工艺复原研究）。', skill_expansion='陶瓷艺术创新（如现代陶艺）创作能力、陶瓷科技（如智能陶瓷）应用技能、陶瓷文化（如茶器设计）传播能力。'  where code='130510TK';
update major set core_course_learning = '新媒体艺术理论（影像/声音/交互）、数字技术（编程/建模/渲染）、媒介理论（媒介进化/技术哲学）、创作方法论（方案/执行/反思）、跨学科实践（艺术+科技）。', practical_skill_development='新媒体装置（如声音可视化）创作实践、交互影像（如观众参与）调试实训、数字内容（如短视频）制作模拟、毕业论文（新媒体艺术的媒介特性研究）。', skill_expansion='元宇宙新媒体（如虚拟直播）运营能力、AI生成内容（如AIGC）工具使用技能、新媒体艺术教育（如工作坊）组织能力。'  where code='130511T';
update major set core_course_learning = '包装设计史（传统包装/现代包装）、包装结构（折叠盒/天地盖/异形盒）、材料选择（纸/塑/金属）、视觉传达（品牌/信息/色彩）、印刷工艺（胶印/凹印/丝印）。', practical_skill_development='包装结构（如食品包装）设计实践、材料测试（如抗压/防潮）实验模拟、视觉传达（如产品手册）设计实训、毕业论文（绿色包装设计策略研究）。', skill_expansion='可持续包装（如可降解材料）设计能力、智能包装（如RFID标签）技术应用技能、包装品牌（如高端礼品）营销实务能力。'  where code='130512T';
update major set core_course_learning = '珠宝史（中西方珠宝史/民族首饰）、首饰设计（造型/比例/镶嵌）、材料工艺（贵金属/宝石/珐琅）、制作技法（失蜡铸造/冷镶/雕刻）、珠宝鉴定（宝石学基础）。', practical_skill_development='首饰设计（如婚戒/吊坠）方案设计实训、材料加工（如黄金锻造）操作实践、制作工艺（如微镶）技术模拟、毕业论文（中国传统首饰工艺传承研究）。', skill_expansion='3D珠宝设计（如MatrixGold）技术应用能力、高级珠宝（如高定首饰）创意技能、珠宝鉴定（如钻石分级）实务能力。'  where code='130513TK';
update major set core_course_learning = '人居设计史（传统村落/现代社区）、人体工程学（居住行为/空间尺度）、材料工艺（木材/混凝土/玻璃）、可持续设计（节能/环保/适老化）、项目管理（预算/进度/质量）。', practical_skill_development='居住空间（如住宅/公寓）方案设计实践、社区规划（如公共空间）节点设计模拟、可持续设计（如被动式房屋）技术实训、毕业论文（适老化人居设计研究）。', skill_expansion='绿色建筑（如LEED认证）设计能力、社区营造（如参与式设计）组织技能、人居设计政策（如《城市居住区规划设计标准》）解读能力。'  where code='130514T';
update major set core_course_learning = '游戏史（主机游戏/PC游戏/手游）、游戏美术（角色/场景/道具）、游戏引擎（Unity/Unreal）、角色设计（原画/建模/绑定）、游戏叙事（剧本/关卡）。', practical_skill_development='游戏角色（如3D建模）设计实践、游戏场景（如场景绘制）制作实训、游戏引擎（如关卡搭建）操作模拟、毕业论文（国风游戏美术设计研究）。', skill_expansion='次世代游戏（如4K画质）美术能力、游戏叙事（如分支剧情）设计技能、游戏美术工具（如ZBrush）高级应用能力。'  where code='130515TK';


INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('12140cb9-177a-4599-a543-b75f4bd9e8ad', '安全技术与管理', '大一：专业认知​
● ​课程学习​：学习安全系统工程、安全生产法规、职业卫生基础等课程，掌握安全管理基本框架。培养风险识别能力。
● ​实践活动​：参加企业安全参观活动，了解生产现场安全管理流程；参与校园安全隐患排查实践。
● ​社团活动​：加入安全协会，参与安全知识竞赛，提升专业认知。

​大二：技能提升​
● ​课程学习​：深入学习事故预防技术、应急救援管理、安全评价等课程，掌握风险评估方法。
● ​技能考证​：报考注册安全工程师（初级）或安全评价师证书，参加培训提升通过率。
● ​实践活动​：到制造企业或建筑工地暑期实习，参与安全巡检和应急预案制定。

​大三：就业准备​
● ​实习​：完成企业毕业实习，独立负责部门安全报表制作和隐患整改跟踪。
● ​求职​：关注大型企业EHS（环境健康安全）岗位招聘，准备事故案例分析面试材料。
● ​职业规划​：目标成为安全主管或咨询顾问，持续学习ISO45001等国际标准，工作后考取中级注册安全工程师。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('1d6ded7d-c9a8-426f-bc6c-17c78776d8b8', '宝玉石鉴定与加工', '大一：专业入门​
● ​课程学习​：学习宝石学基础、矿物结晶学、首饰手绘设计等课程，掌握宝石分类和光学特性。
● ​实践活动​：实训室操作折射仪/偏光镜，参与校内宝石鉴定比赛。
● ​社团活动​：加入珠宝设计社团，参观珠宝展销会。

​大二：技能提升​
● ​课程学习​：深入学习钻石分级、翡翠鉴定、珠宝镶嵌工艺等课程，掌握NGTC或GIA鉴定体系。
● ​技能考证​：报考GIC（地质大学）宝石鉴定师或首饰设计师证书。
● ​实践活动​：暑期到珠宝检测机构实习，参与鉴定证书出具流程。

​大三：就业准备​
● ​实习​：在珠宝企业完成毕业实习，负责柜台商品真伪筛查和客户答疑。
● ​求职​：应聘珠宝质检机构或品牌门店鉴定师，制作个人鉴定案例集。
● ​职业规划​：成为资深鉴定师或独立工作室主理人，持续跟进合成宝石技术，拓展直播鉴宝技能。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('6ff1ff26-8a66-486c-ab9b-3b58595b6cfa', '保健食品质量与管理', '大一：专业认知​
● ​课程学习​：学习食品化学、营养学基础、保健食品法规，了解功能成分作用机制。
● ​实践活动​：参与实验室功效成分检测实训，设计膳食方案比赛。
● ​社团活动​：加入健康产业协会，调研市售保健品标签合规性。

​大二：技能提升​
● ​课程学习​：深入学习GMP管理、保健食品检验技术、质量管理体系（ISO22000）。
● ​技能考证​：报考食品安全管理师或公共营养师证书。
● ​实践活动​：到保健食品厂暑期实习，参与生产线卫生审核和产品抽检。

​大三：就业准备​
● ​实习​：完成企业毕业实习，负责原料验收记录和产品留样管理。
● ​求职​：关注药企或检测机构质检岗位，整理GMP审计报告案例。
● ​职业规划​：目标成为质量经理或合规专员，考取ISO内审员资格，未来攻读食品科学在职硕士。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('f1e0eaf1-ed2b-4265-ac6f-2ea060fc292a', '保险实务', '大一：行业了解​
● ​课程学习​：学习保险学原理、金融基础、风险管理概论，了解险种分类。
● ​实践活动​：模拟保险销售演练，参与理赔案例分析比赛。
● ​社团活动​：加入金融保险社团，走访保险公司营业部。

​大二：技能培养​
● ​课程学习​：深入学习人身保险、财产保险、保险营销技巧，掌握核保规则。
● ​技能考证​：报考保险代理人资格证或银行保险从业资格证。
● ​实践活动​：暑期到保险公司实习，参与客户需求分析和保单规划。

​大三：就业准备​
● ​实习​：完成保险公司毕业实习，独立处理续保提醒和简单理赔材料初审。
● ​求职​：应聘保险顾问或银行保险专员岗位，准备客户服务案例集。
● ​职业规划​：目标晋升团队主管或培训师，积累RFC（财务顾问师）认证，未来转向保险精算方向。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('4832e445-4722-4176-8ea8-97e5cc7c9175', '保险实务(保险理赔方向)', '大一：行业了解​
● ​课程学习​：学习保险学原理、金融基础、风险管理概论，了解险种分类。
● ​实践活动​：模拟保险销售演练，参与理赔案例分析比赛。
● ​社团活动​：加入金融保险社团，走访保险公司营业部。

​大二：技能培养​
● ​课程学习​：深入学习人身保险、财产保险、保险营销技巧，掌握核保规则。
● ​技能考证​：报考保险代理人资格证或银行保险从业资格证。
● ​实践活动​：暑期到保险公司实习，参与客户需求分析和保单规划。

​大三：就业准备​
● ​实习​：在保险公司理赔部实习，学习车险人伤案件调查或财产险定损流程。
● ​求职​：专注理赔员岗位，准备交通事故责任判定或医疗审核案例分析。
● ​职业规划​：成为资深理赔师，学习保险公估知识，考取核赔师（CPCU）证书。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('bb56255d-6948-4836-86c6-58abfddccdd1', '保险实务(金融保险)', '大一：行业了解​
● ​课程学习​：学习保险学原理、金融基础、风险管理概论，了解险种分类。
● ​实践活动​：模拟保险销售演练，参与理赔案例分析比赛。
● ​社团活动​：加入金融保险社团，走访保险公司营业部。

​大二：技能培养​
● ​课程学习​：增加金融理财规划、证券投资等课程，掌握资产配置工具。
● ​技能考证​：报考基金从业资格证或AFP（金融理财师）。● ​实践活动​：暑期到保险公司实习，参与客户需求分析和保单规划。

​大三：就业准备​
● ​实习​：完成保险公司毕业实习，独立处理续保提醒和简单理赔材料初审。
● ​求职​：应聘保险顾问或银行保险专员岗位，准备客户服务案例集。
● ​职业规划​：目标银行理财经理或家族办公室顾问，学习信托、税务筹划知识。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('5ab4ae63-d480-45f4-8245-1ff98863183a', '表演艺术', '​大一：专业基础​
● ​课程学习​：学习表演基础、台词训练、形体控制，掌握舞台表现技巧。
● ​实践活动​：参与校园话剧排演，参加即兴表演工作坊。
● ​社团活动​：加入话剧社，组织社区公益演出。

​大二：技能提升​
● ​课程学习​：深入学习角色塑造、镜头表演、声乐训练，掌握影视与舞台双栖能力。
● ​技能考证​：报考演出经纪人资格证或普通话一级证书。
● ​实践活动​：暑期到剧场或影视剧组实习，担任群演或导演助理。

​大三：就业准备​
● ​实习​：在演艺公司完成毕业实习，参与商业演出策划或艺人统筹。
● ​求职​：应聘演员、艺考导师或活动主持岗位，制作个人表演作品集。
● ​职业规划​：成立个人工作室或签约经纪公司，持续进修导演课程，拓展短视频内容创作。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('276b3d16-a4ff-4256-8b5c-755d5719b13b', '冰雪设施运维与管理', '大一：专业认知​
● ​课程学习​：学习冰雪运动基础、制冷原理、雪场设备概论，了解造雪系统构成。
