INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('4a84dfbe-c79c-4b29-b587-597de27e77e1', '材料成型及控制技术(飞机制造)', '大一：专业认知与基础​
● ​课程学习​：工程力学、航空工程材料、飞机构造基础、复合材料成型工艺，掌握飞机结构材料特性与成型原理
。
● ​实践活动​：参观飞机装配线，参与钣金/复材基础实训，加入航模社设计简易飞行器。
● ​考证准备​：考取CAD绘图员证书。

​大二：技能深化与认证​
● ​课程学习​：飞机结构制造技术、数字化装配工艺、飞机损伤检测，学习RTM（树脂传递模塑）等先进工艺
。
● ​技能考证​：考取航空制造业“复合材料成型工”或“无损检测员”初级证书。
● ​实训​：在飞机制造厂实习，参与机翼/机身部件成型与质检流程。

​大三：就业与职业规划​
● ​实习​：在商飞、中航工业等企业完成毕业实习，独立负责零部件工艺优化报告。
● ​求职方向​：飞机结构工程师、复材工艺师，聚焦航空制造企业技术岗。
● ​职业规划​：目标成为高级制造工程师，持续学习自动化成型技术（如3D打印金属构件），考取“航空制造工程师”资格', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('7a2e0eda-6b95-41e6-8f71-460d774dfd97', '财富管理', '大一：行业认知​
● ​课程学习​：金融学基础、会计原理、经济法，理解财富管理市场规则。
● ​实践活动​：模拟投资大赛，参加银行/证券公司的开放日活动。
