。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('401988e8-b657-4649-a305-a59757a3cd79', '城市轨道交通车辆制造与维护', '​大一：制造基础​
● ​课程学习​：机械制图、电气控制、车辆总装工艺，掌握车体焊接与线束安装标准
