INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('374487cd-257b-4121-b2ba-3e6ad9a308ee', '电信服务与管理', '大一：行业认知与基础技能
● ​核心课程：现代通信技术概论、客户行为分析、服务礼仪、办公自动化
