INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('3f28017d-ce14-4ec5-ab31-24f41c4fff8a', '空中乘务', '大一：职业认知
● ​课程学习：学习民航概论、客舱安全、服务心理学等课程，掌握应急设备操作及CRM团队协作流程。
● ​实践活动：操作模拟舱完成紧急撤离演练；参与贵宾室茶艺服务实训。
● ​社团活动：加入礼仪协会，开展“微笑服务”校园公益活动。

​大二：技能强化
