INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('24e65098-c99b-405f-a92e-72eaec270091', '铁道通信与信息化技术', '大一：专业认知
● ​课程学习：学习现代通信技术、电子技术基础、铁道基站设备原理等课程，掌握CAN总线通信协议及光缆接续标准。
● ​实践活动：操作模拟平台完成列车无线调度系统调试；参与校园5G-R通信组网竞赛。
● ​社团活动：加入轨道交通创新社，拆解高铁CTCS-3级列控系统硬件结构。

​大二：运维实战
● ​课程学习：深入学习LTE-R技术、铁路数字调度通信、通信线路工程等课程，掌握基站故障定位算法及冗余备份配置技术。
● ​技能考证：报考铁路通信工（中级）或华为HCIA-5G认证，通过考试验证技能；可参加中国通号集团信号特训营。
● ​实践活动：到地铁信号工区暑期实习，优化车地通信延迟问题，数据传输丢包率降至0.1%。

​大三：就业冲刺
