INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('d0f3ef97-a41a-4af7-9be0-73740c9e4e25', '现代物流管理', '大一：行业入门
● ​课程学习：学习物流系统规划、智能仓储基础、机械制图等课程，掌握AGV路径规划原理及货架受力分析计算。
● ​实践活动：操作WMS系统完成入库流程模拟；参与校园智慧物流沙盘竞赛。
● ​社团活动：加入机器人协会，拆解研究分拣机器人机械结构。

​大二：运营实战
● ​课程学习：深入学习供应链大数据分析、物流自动化控制、跨境物流管理等课程，掌握数字孪生仓库建模及关务合规操作。
● ​技能考证：报考物流工程师（初级）或国际货运代理证书，通过考试强化资质；可参加京东物流“青流计划”培训。
● ​实践活动：到顺丰智能仓暑期实习，参与无人分拣线故障诊断系统开发，降低卡件率至0.3%。

​大三：职业突破
