INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('697870ee-c3e0-4459-8f51-a2a32f731ec9', '药品生产技术', '大一：行业认知
● ​课程学习：学习GMP管理规范、微生物发酵技术、制药设备基础等课程，掌握菌种斜面培养及无菌操作流程。
● ​实践活动：操作50L发酵罐完成抗生素模拟生产；参与校园GMP模拟车间清洁验证项目。
● ​社团活动：加入生物制药协会，调研mRNA疫苗冻干工艺进展。

​大二：工艺深化
● ​课程学习：深入学习生物分离纯化、药品合成反应、制剂工艺优化等课程，掌握亲和层析技术和PAT过程分析技术。
● ​技能考证：报考生化药品提取工（中级）或执业药师资格证，通过考试强化资质；可参加ISO13485医疗器械质量管理培训。
● ​实践活动：到药企暑期实习，参与单抗纯化工艺优化，建立层析柱寿命预测模型。

​大三：职业发展
● ​实习：完成疫苗生产企业毕业实习，独立设计核酸疫苗冻干保护剂配方，通过加速稳定性测试。
● ​求职：关注药明生物、凯莱英等企业研发岗招聘，准备工艺优化报告和纯化色谱图集，面试突出无菌操作规范。
● ​职业规划：目标为工艺工程师；持续学习细胞连续培养技术，可攻读生物工程硕士或考取PDA国际认证。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('d9c1627a-f9e3-4a14-be2a-d7a89f3cee8c', '药品生物技术', '大一：专业基础
● ​课程学习：学习微生物学、生物化学、GMP管理规范等课程，掌握发酵罐操作标准及质粒提取技术，熟悉《中国药典》药品检验核心条款。
● ​实践活动：操作超净工作台完成大肠杆菌接种实训；参与校园益生菌产品研发项目（完成菌种筛选≥3种）。
● ​社团活动：加入生物科技协会，调研mRNA疫苗技术路径；参与省级生物实验技能竞赛选拔。

​大二：技术深化
● ​课程学习：深入学习基因工程、细胞培养技术、生物分离纯化等课程，掌握PCR扩增条件优化及Western Blot蛋白检测技术。
● ​技能考证：报考生物发酵工（中级）或ISO13485内审员证书，通过考试验证技能；可参加药明生物“菁英计划”培训提升实操能力。
● ​实践活动：到药企质检部暑期实习，优化抗体纯化工艺，产物纯度提升至98%。

​大三：职业发展
● ​实习：完成华熙生物毕业实习，开发胶原蛋白酶解工艺，通过国家药监局备案。
● ​求职：关注同仁堂、药明康德招聘，准备实验报告和工艺优化方案，面试突出CRISPR技术应用能力。
● ​职业规划：目标为生物制药工程师；持续学习类器官培养技术，可考执业药师或攻读生物工程专升本。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
