INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('d3c8a2f6-6918-4a74-b197-d911f21bb992', '医疗器械经营与服务', '大一：专业基础
● ​课程学习：学习医疗器械学概论、GSP管理规范、医学基础等课程，掌握无菌耗材验收标准及冷链温控流程。
● ​实践活动：操作心电图机完成设备质检实训；参与校园医疗器械电商模拟运营。
● ​社团活动：加入医械科普队，调研DTP药房高值耗材管理模式。

​大二：运营实战
● ​课程学习：深入学习医疗器械法规、营销策划、医院设备管理实务等课程，掌握招标文件编制及UDI追溯系统操作。
● ​技能考证：报考医疗器械购销员或ISO13485内审员证书，通过考试验证技能；可参加微创医疗学术推广培训。
● ​实践活动：到联影医疗暑期实习，参与PET-CT装机全流程管理，客户满意度达100%。

​大三：职业突破
● ​实习：完成三甲医院设备科毕业实习，优化腔镜设备调度方案，利用率提升40%。
● ​求职：关注迈瑞医疗、国药器械招聘，准备招标方案和客户资源表，面试展示合规风控能力。
● ​职业规划：目标为区域销售经理；持续学习AI辅助诊断设备推广策略，可考医疗器械管理师或攻读生物医学工程专升本。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('f0e5ef92-071a-490f-83bf-9f19e8a59d55', '医疗器械维护与管理', '大一：专业入门
● ​课程学习：学习医用电子技术、解剖生理学、医疗器械概论等课程，掌握监护仪参数校准方法及无菌耗材验收标准。
● ​实践活动：拆装输液泵完成故障诊断实训；参与医院设备科巡检实践。
● ​社团活动：加入医工协会，调研CT球管寿命预测技术。

​大二：技术融合
● ​课程学习：深入学习医学影像设备原理、有源设备检测技术、医院设备管理等课程，掌握DR图像质量评价及呼吸机气路系统检修技术。
● ​技能考证：报考医疗器械维修工程师或临床工程师证书，通过考试获取执业资质；可参加GE医疗CT设备专项培训。
● ​实践活动：到三甲医院暑期实习，优化超声探头保养流程，维修成本降低30%。

​大三：就业冲刺
● ​实习：完成医疗器械公司毕业实习，主导内窥镜光学系统维护方案，故障返修率降至5%。
● ​求职：关注联影医疗、西门子医疗招聘，准备维修案例集和质控报告，面试突出院感防控能力。
● ​职业规划：定位为医工科主任；持续学习AI辅助诊断技术，可考CE认证或攻读生物医学工程专升本', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('bfa44b95-37eb-4531-9f43-b928da16594c', '医学检验技术', '大一：专业基础
● ​课程学习：学习临床检验基础、生物化学、医学统计学等课程，掌握血细胞分析仪质控流程及ELISA检测标准曲线绘制。
● ​实践活动：操作全自动生化仪完成肝功能检测实训；参与校园PCR实验室生物安全演练。
● ​社团活动：加入医学科研社，研究肿瘤标志物联合检测方案。

​大二：智能检验
● ​课程学习：深入学习分子诊断技术、智能检验设备应用、实验室信息管理等课程，掌握基因测序数据分析及AI病理图像识别技术。
● ​技能考证：报考临床医学检验技师或ISO15189内审员证书，通过考试获取从业资质；可参加华大基因生信分析培训。
● ​实践活动：到三甲医院检验科暑期实习，开发检验报告自动审核规则，TAT时间缩短50%。

​大三：职业发展
● ​实习：完成第三方检测机构毕业实习，构建新冠变异株快速筛查流程，检出灵敏度达99.8%。
● ​求职：关注金域医学、迪安诊断招聘，准备质控报告和新技术评估方案，面试突出危急值处理能力。
● ​职业规划：定位为实验室主管；持续学习液体活检技术，可考病理学技师或攻读医学检验技术专升本', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('ab213863-8857-45c9-ac1b-849953709eae', '医学美容技术', '大一：美学基础
● ​课程学习：学习皮肤生理学、美容药物学、医学美学设计等课程，掌握VISIA皮肤检测仪操作及面部黄金比例评估标准。
● ​实践活动：操作光子嫩肤仪完成模拟实训；参与社区“科学护肤”义诊活动。
● ​社团活动：加入医美科普社，研究轻医美消费趋势。

​大二：技术专精
● ​课程学习：深入学习激光美容技术、微整形注射解剖学、美容外科护理等课程，掌握超声炮抗衰方案设计及玻尿酸注射层次控制。
● ​技能考证：报考美容主诊医师备案或皮肤管理师证书，通过考试验证技能；可参加华熙生物“再生医学”工作坊。
● ​实践活动：到医美机构暑期实习，独立完成30例客户面部分析报告，方案采纳率90%。

​大三：职业突破
● ​实习：完成华韩整形毕业实习，开发“敏肌修复”联合疗法套餐，客户续卡率提升35%。
● ​求职：关注美莱医疗、薇琳医美招聘，准备客户案例集和疗效对比图，面试展示并发症处理能力。
● ​职业规划：目标为技术院长；持续学习干细胞再生技术，可考整形外科医师或攻读医疗美容技术专升本', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('69677eb9-0051-4e29-9a8d-5a93dbd02b8f', '医学美容技术(中医美容技术)', '大一：专业基础
● ​课程学习：学习中医基础理论、美容解剖学、芳香疗法等课程，掌握面部经络刮痧及九种体质辨识方法。
● ​实践活动：操作真空罐完成背部排毒护理；参与社区中医美容义诊活动。
● ​社团活动：加入汉方美容工坊，研制茯苓美白面膜配方。

​大二：技术融合
● ​课程学习：深入学习中医美容学、美容皮肤科学、光电美容技术等课程，掌握针灸祛斑技法及激光参数调节原则。
● ​技能考证：报考美容师（高级）或中医预防保健调理证书，通过考试验证技能；可参加CIDESCO国际美容认证培训。
● ​实践活动：到医美机构暑期实习，设计“三伏灸+中药面膜”祛痘方案，有效率提升90%。

​大三：职业突破
● ​实习：完成整形医院毕业实习，开发产后中医康复疗程，客户回购率45%。
● ​求职：关注薇琳医美、朗姿股份招聘，准备疗程案例集和客户画像，面试展示非遗技术应用能力。
● ​职业规划：定位为技术总监；持续学习干细胞美容技术，可考国际美容医师或攻读中医美容学专升本。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('85782f6a-a435-4ccb-bb60-6dab6274731b', '医学生物技术', '大一：专业基础
