● ​职业规划：目标为生态项目经理；持续学习植物工厂AI调控，可考LEED AP或攻读风景园林硕士。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
