INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('1f89964c-c7c7-4f0e-bc39-04787d90275a', '中文', '大一：专业认知
● ​课程学习：学习现代汉语、文学概论、中国古代文学等基础课程，掌握语言文字规范及文学发展脉络，培养文本解读与写作能力。参与经典文学作品精读训练，提升文学鉴赏水平。
● ​实践活动：参加校园文学社创作工作坊，完成短篇小说或诗歌习作；参与校报采编实习，实践新闻稿撰写与编辑排版。
● ​社团活动：加入国学社或辩论社，参与经典诵读比赛和方言文化调研活动，增强文化传承意识。

​大二：技能提升
