● ​职业规划：目标为研发主厨；持续学习分子甜品技术，可考烹饪名师或攻读食品科学与工程专升本。', 'ASSOCIATE'::public."majortype");
INSERT INTO public.major
(code, "name", studyingsuggestion, "type")
VALUES('c11a9d56-e990-41a0-be99-e9b705993341', '中药材生产与加工', '大一：专业入门
